import { api } from 'lwc';
import LightningPrimitiveOverlay from 'lightning/primitiveOverlay';
export default class OverlayPanel extends LightningPrimitiveOverlay {
    @api
    header = 'Header';
    @api
    body = 'Body';
    handleDismiss() {
        this.close('dismiss');
    }
    hasFocus = false;
    renderedCallback() {
        if (!this.hasFocus) {
            const close = this.template.querySelector('div > button');
            close.focus();
            this.hasFocus = true;
        }
    }
}
